var src = $('Build Sonnet request').item.json;
var resp = $input.item.json;
var out = { id: src.id, source_slug: src.source_slug, title: src.title, body: src.body };
try {
  if (resp && resp.error) throw new Error((resp.error && resp.error.message) ? resp.error.message : 'anthropic error');
  if (resp && resp.stop_reason === 'max_tokens') throw new Error('max_tokens hit');
  var block = (resp && resp.content && resp.content[0]) ? resp.content[0] : null;
  var txt = (block && block.text) ? block.text : '';
  var T = '###TITLE###', B = '###BODY###';
  var ti = txt.indexOf(T), bi = txt.indexOf(B);
  if (ti < 0 || bi < 0) throw new Error('missing delimiters in response');
  out.title_raw = txt.slice(ti + T.length, bi).trim();
  out.body_raw = txt.slice(bi + B.length).trim();
  out.translation_engine = 'sonnet';
} catch (e) {
  out._error = 'sonnet: ' + String((e && e.message) ? e.message : e).slice(0, 300);
}
return { json: out };

// Deterministic bird-name correction (ported from _shared/bird-names-et.ts) + build PATCH.
// Dictionary = Linnud.txt (EOU checklist) hosted in Storage, cached 6h in workflow static data.
var items = $input.all();

function parseLinnud(tsv) {
  var map = {};
  var lines = String(tsv || '').replace(/^\uFEFF/, '').split(/\r?\n/).filter(Boolean);
  if (lines.length < 2) return map;
  var header = lines[0].split('\t').map(function (c) { return c.trim(); });
  var li = header.indexOf('nimi_lk');
  var ei = header.indexOf('nimi_ek');
  if (li < 0 || ei < 0) return map;
  for (var i = 1; i < lines.length; i++) {
    var cells = lines[i].split('\t');
    var est = String(cells[ei] || '').replace(/\s*\([^)]*\)\s*/g, ' ').replace(/\s+/g, ' ').trim();
    if (!est) continue;
    var aliases = String(cells[li] || '').split(',');
    for (var a = 0; a < aliases.length; a++) {
      var key = aliases[a].toLowerCase().replace(/\*/g, '').replace(/[()\[\]]/g, '').replace(/\s+/g, ' ').trim();
      if (key && !map[key]) map[key] = est;
    }
  }
  return map;
}

var CALQUES = [
  [/\bDalmaatsia\s+pelikan(i|it|ile|is|ist|iks|iga|ina)?\b/gi, 'käharpelikan$1'],
  [/\bDalmaatia\s+pelikan(i|it|ile|is|ist|iks|iga|ina)?\b/gi, 'käharpelikan$1'],
  [/\bSabatiigli\s+kiivitaja(t|le|s|st|ks|ga|na)?\b/gi, 'stepikiivitaja$1'],
  [/\bkannusvästrik(u|ut|ule|us|ust|uks|uga|una|ud|ute|uid|utes|utega|uteta)?\b/gi, 'valgekael-kiivitaja$1'],
  [/\btuttvart-koiras(t|tega|le|s|st|ks|ina)?\b/gi, 'tutka-isane$1'],
  [/\btuttvart-koirased(?=\b)/gi, 'tutka-isased'],
  [/\bkoirased\b/gi, 'isased'],
  [/\bkoirastega\b/gi, 'isastega'],
  [/\bkoirast\b/gi, 'isast'],
  [/\bkoiraste\b/gi, 'isaste'],
  [/\btuttvartidel\b/gi, 'tutkadel'],
  [/\btuttvartid\b/gi, 'tutkad'],
  [/\bvappubukett(i|it|ile|is|ist|iks|iga|ina)?\b/gi, 'kevadlille$1'],
  [/\bvappuõis(t|tega|le|s|st|ks|ed)?\b/gi, 'kevadlille$1']
];

function fixCalques(t) { if (!t) return t; var r = t; for (var i = 0; i < CALQUES.length; i++) { r = r.replace(CALQUES[i][0], CALQUES[i][1]); } return r; }

function fixBirdNames(text, latinToEt) {
  if (!text) return text;
  var normalized = String(text)
    .replace(/\(\s*\*\s*([A-Z][a-z]+\s+[a-z]+)\s*\*\s*\)/g, '($1)')
    .replace(/\(\s*_\s*([A-Z][a-z]+\s+[a-z]+)\s*_\s*\)/g, '($1)')
    .replace(/\(\s*<i>\s*([A-Z][a-z]+\s+[a-z]+)\s*<\/i>\s*\)/gi, '($1)');
  var result = normalized.replace(/([\p{L}\-]+(?:\s+[\p{L}\-]+){0,3})\s*\(([A-Z][a-z]+\s+[a-z]+)\)/gu, function (m, _e, latin) {
    var c = latinToEt[latin.toLowerCase()];
    return c ? (c + ' (' + latin + ')') : m;
  });
  result = result.replace(/(?<!\()(?<!\w)\b([A-Z][a-z]+\s+[a-z]+)\b(?!\))/g, function (m, latin) {
    var c = latinToEt[latin.toLowerCase()];
    return c ? (c + ' (' + latin + ')') : m;
  });
  return fixCalques(result);
}

// load + cache dictionary
var latinToEt;
var raw = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://eenwcyuyugyrjgpivxrq.supabase.co/storage/v1/object/public/bird-avatars/meta/Linnud.txt',
  json: false
});
latinToEt = parseLinnud(String(raw));

var CYR = {'а':'a','б':'b','в':'v','г':'g','д':'d','е':'e','ё':'jo','ж':'zh','з':'z','и':'i','й':'j','к':'k','л':'l','м':'m','н':'n','о':'o','п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'h','ц':'ts','ч':'ch','ш':'sh','щ':'sch','ъ':'','ы':'y','ь':'','э':'e','ю':'ju','я':'ja'};
function deCyrillic(s){ if(!s) return s; return String(s).replace(/[\u0400-\u04FF]/g, function(ch){ var low=ch.toLowerCase(); var r=CYR[low]; if(r===undefined) return ''; if(ch!==low && r){ return r.charAt(0).toUpperCase()+r.slice(1); } return r; }); }

var out = [];
for (var k = 0; k < items.length; k++) {
  var it = items[k].json;
  var patch;
  if (it._error || (!it.title_raw && !it.body_raw)) {
    patch = {
      translation_v2_status: 'error',
      translation_v2_error: String(it._error || 'empty translation').slice(0, 500)
    };
  } else {
    patch = {
      title_et_v2: fixBirdNames(deCyrillic(String(it.title_raw || '')), latinToEt) || null,
      body_et_v2: fixBirdNames(deCyrillic(String(it.body_raw || '')), latinToEt) || null,
      translation_engine: it.translation_engine || null,
      translation_v2_status: 'done',
      translation_v2_error: null,
      translated_v2_at: new Date().toISOString()
    };
  }
  out.push({ json: { id: it.id, patch: patch } });
}
return out;
